function esc(str) {
  return String(str ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function redirect(location, extraHeaders = {}) {
  return new Response(null, { status: 302, headers: { Location: location, ...extraHeaders } });
}

function html(body, status = 200) {
  return new Response(body, { status, headers: { "Content-Type": "text/html; charset=UTF-8" } });
}

function jsonResponse(obj, status = 200) {
  return new Response(JSON.stringify(obj), { status, headers: { "Content-Type": "application/json" } });
}

function toHex(buffer) {
  return [...new Uint8Array(buffer)].map((b) => b.toString(16).padStart(2, "0")).join("");
}

function randomSalt() {
  return toHex(crypto.getRandomValues(new Uint8Array(16)));
}

async function hashPassword(password, salt) {
  const enc = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey("raw", enc.encode(password), "PBKDF2", false, ["deriveBits"]);
  const bits = await crypto.subtle.deriveBits(
    { name: "PBKDF2", salt: enc.encode(salt), iterations: 100000, hash: "SHA-256" },
    keyMaterial,
    256
  );
  return toHex(bits);
}

async function verifyPassword(password, salt, expectedHash) {
  const actual = await hashPassword(password, salt);
  return actual === expectedHash;
}

async function hmacToken(secret, token) {
  const enc = new TextEncoder();
  const key = await crypto.subtle.importKey("raw", enc.encode(secret), { name: "HMAC", hash: "SHA-256" }, false, ["sign"]);
  const sig = await crypto.subtle.sign("HMAC", key, enc.encode(token));
  return toHex(sig);
}

function randomSecretToken() {
  return toHex(crypto.getRandomValues(new Uint8Array(24)));
}

function parseCookies(req) {
  const header = req.headers.get("Cookie") || "";
  const out = {};
  header.split(";").forEach((part) => {
    const idx = part.indexOf("=");
    if (idx === -1) return;
    const k = part.slice(0, idx).trim();
    const v = part.slice(idx + 1).trim();
    if (k) out[k] = v;
  });
  return out;
}

function sessionCookieHeader(value) {
  return `${SESSION_COOKIE}=${value}; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=604800`;
}

function deviceLabelFromUA(ua) {
  ua = ua || "";
  let os = "دستگاه ناشناس";
  if (/android/i.test(ua)) os = "اندروید";
  else if (/iphone|ipad|ios/i.test(ua)) os = "iOS";
  else if (/windows/i.test(ua)) os = "ویندوز";
  else if (/mac os/i.test(ua)) os = "مک";
  else if (/linux/i.test(ua)) os = "لینوکس";
  let browser = "";
  if (/edg\//i.test(ua)) browser = "Edge";
  else if (/chrome\//i.test(ua)) browser = "Chrome";
  else if (/firefox\//i.test(ua)) browser = "Firefox";
  else if (/safari\//i.test(ua)) browser = "Safari";
  return browser ? `${os} - ${browser}` : os;
}

async function createSession(env, userId, request) {
  const token = randomSecretToken();
  const secret = await ensureSessionSecret(env);
  const tokenHash = await hmacToken(secret, token);
  const ua = request.headers.get("User-Agent") || "";
  const ip = request.headers.get("CF-Connecting-IP") || "";
  const now = Date.now();
  await env.DB.prepare(
    `INSERT INTO sessions (user_id, token_hash, device_label, ip, created_at, last_seen_at) VALUES (?, ?, ?, ?, ?, ?)`
  ).bind(userId, tokenHash, deviceLabelFromUA(ua), ip, now, now).run();
  return token;
}

async function getCurrentSession(request, env) {
  const cookies = parseCookies(request);
  const token = cookies[SESSION_COOKIE];
  if (!token) return null;
  const secret = await ensureSessionSecret(env);
  const tokenHash = await hmacToken(secret, token);
  const session = await env.DB.prepare("SELECT * FROM sessions WHERE token_hash = ?").bind(tokenHash).first();
  if (!session) return null;
  return session;
}

async function getCurrentUserId(request, env) {
  const session = await getCurrentSession(request, env);
  return session ? session.user_id : null;
}

async function destroySessionByToken(env, token) {
  const secret = await ensureSessionSecret(env);
  const tokenHash = await hmacToken(secret, token);
  await env.DB.prepare("DELETE FROM sessions WHERE token_hash = ?").bind(tokenHash).run();
}

