const COLUMN_MIGRATIONS = [
  { table: "bots", column: "smart_reaction", ddl: "ALTER TABLE bots ADD COLUMN smart_reaction INTEGER NOT NULL DEFAULT 0" },
  { table: "users", column: "avatar_url", ddl: "ALTER TABLE users ADD COLUMN avatar_url TEXT" },
  {
    table: "users",
    column: "notification_prefs",
    ddl: `ALTER TABLE users ADD COLUMN notification_prefs TEXT NOT NULL DEFAULT '{"error_alerts":true,"login_alerts":true,"weekly_summary":false}'`,
  },
];

async function tableHasColumn(DB, table, column) {
  const info = await DB.prepare(`SELECT name FROM pragma_table_info('${table}')`).all();
  return (info.results || []).some((row) => row.name === column);
}

async function applyColumnMigrations(DB) {
  for (const { table, column, ddl } of COLUMN_MIGRATIONS) {
    try {
      if (!(await tableHasColumn(DB, table, column))) {
        await DB.prepare(ddl).run();
      }
    } catch (err) {
      if (!/duplicate column name/i.test(String(err && err.message))) throw err;
    }
  }
}

async function runSchemaInitialization(env) {
  await env.DB.batch(SCHEMA_STATEMENTS.map((sql) => env.DB.prepare(sql)));
  await applyColumnMigrations(env.DB);
}

let dbInitPromise = null;

async function ensureDatabase(env) {
  if (!dbInitPromise) {
    dbInitPromise = runSchemaInitialization(env).catch((err) => {
      dbInitPromise = null;
      throw err;
    });
  }
  return dbInitPromise;
}


let sessionSecretCache = null; 
let sessionSecretPromise = null; 

async function ensureSessionSecret(env) {
  if (sessionSecretCache) return sessionSecretCache;
  if (!sessionSecretPromise) {
    sessionSecretPromise = (async () => {
      const existing = await env.DB.prepare("SELECT value FROM app_config WHERE key = 'session_secret'").first();
      if (existing && existing.value) return existing.value;

      const candidate = toHex(crypto.getRandomValues(new Uint8Array(32))); // 256 bits
      await env.DB.prepare(
        "INSERT INTO app_config (key, value, created_at) VALUES ('session_secret', ?, ?) ON CONFLICT(key) DO NOTHING"
      )
        .bind(candidate, Date.now())
        .run();

      const row = await env.DB.prepare("SELECT value FROM app_config WHERE key = 'session_secret'").first();
      if (!row || !row.value) throw new Error("Failed to persist session secret");
      return row.value;
    })().catch((err) => {
      sessionSecretPromise = null;
      throw err;
    });
  }
  const value = await sessionSecretPromise;
  sessionSecretCache = value; 
  return value;
}

