function apiUrl(token, method) {
  return `https://api.telegram.org/bot${token}/${method}`;
}

async function callApi(token, method, params = {}) {
  try {
    const res = await fetch(apiUrl(token, method), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(params),
    });
    return await res.json();
  } catch (err) {
    return { ok: false, description: String(err) };
  }
}

const tg = {
  getMe: (token) => callApi(token, "getMe"),
  setWebhook: (token, url, secretToken) =>
    callApi(token, "setWebhook", {
      url,
      secret_token: secretToken,
      allowed_updates: ["message", "channel_post", "edited_message"],
    }),
  deleteWebhook: (token) => callApi(token, "deleteWebhook"),
  sendMessage: (token, chatId, text) => callApi(token, "sendMessage", { chat_id: chatId, text }),
  setMessageReaction: (token, chatId, messageId, emoji, isBig = false) =>
    callApi(token, "setMessageReaction", {
      chat_id: chatId,
      message_id: messageId,
      reaction: [{ type: "emoji", emoji }],
      is_big: !!isBig,
    }),
};

export function pickRandomEmoji(emojiList) {
  if (!Array.isArray(emojiList) || emojiList.length === 0) return "❤";
  return emojiList[Math.floor(Math.random() * emojiList.length)];
}

export function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

