async function handleWebhook(request, env, botId) {
  const secretHeader = request.headers.get("X-Telegram-Bot-Api-Secret-Token");
  const bot = await db.getBotById(env.DB, botId);
  if (!bot) return new Response("not found", { status: 404 });
  if (secretHeader !== bot.webhook_secret) return new Response("forbidden", { status: 403 });
  if (bot.status !== "active") return new Response("ok");

  let update;
  try {
    update = await request.json();
  } catch {
    return new Response("bad request", { status: 400 });
  }

  const emojis = JSON.parse(bot.emojis || '["❤"]');

  try {
    if (update.message) {
      const msg = update.message;
      const text = (msg.text || "").trim();
      if (text === "/start") {
        await tg.sendMessage(bot.token, msg.chat.id, bot.welcome_message);
      } else {
        const emoji = bot.smart_reaction ? pickSmartEmoji(text, emojis) : pickRandomEmoji(emojis);
        const res = await tg.setMessageReaction(bot.token, msg.chat.id, msg.message_id, emoji);
        if (res.ok) await db.incrementReaction(env.DB, bot.id);
      }
    } else if (update.channel_post) {
      const msg = update.channel_post;
      const text = (msg.text || msg.caption || "").trim();
      const emoji = bot.smart_reaction ? pickSmartEmoji(text, emojis) : pickRandomEmoji(emojis);
      const res = await tg.setMessageReaction(bot.token, msg.chat.id, msg.message_id, emoji);
      if (res.ok) await db.incrementReaction(env.DB, bot.id);
    }
  } catch (err) {
    await db.setBotError(env.DB, bot.id, String(err).slice(0, 300));
  }

  return new Response("ok");
}


function parseCsvLine(line) {
  const firstComma = line.indexOf(",");
  if (firstComma === -1) return null;
  const token = line.slice(0, firstComma).trim();
  const rest = line.slice(firstComma + 1);
  const secondComma = rest.indexOf(",");
  let emojiPart, welcome;
  if (secondComma === -1) {
    emojiPart = rest.trim();
    welcome = "سلام خوش آمدید 👋";
  } else {
    emojiPart = rest.slice(0, secondComma).trim();
    welcome = rest.slice(secondComma + 1).trim() || "سلام خوش آمدید 👋";
  }
  const emojis = emojiPart
    .split(/[|،]/)
    .map((e) => e.trim())
    .filter((e) => ALLOWED_REACTION_EMOJIS.includes(e));
  if (!token) return null;
  return { token, emojis: emojis.length ? emojis : ["❤"], welcome };
}

async function handleRequest(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    const webhookMatch = path.match(/^\/webhook\/(\d+)$/);
    if (webhookMatch) return handleWebhook(request, env, Number(webhookMatch[1]));

    if (path === "/setup") {
      const userCount = await db.countUsers(env.DB);
      if (userCount > 0) return redirect("/login");
      if (method === "GET") return html(loginPage({ hasUsers: false }));
      if (method === "POST") {
        const form = await request.formData();
        const username = (form.get("username") || "").toString().trim();
        const password = (form.get("password") || "").toString();
        if (!username || password.length < 6) {
          return html(loginPage({ hasUsers: false, error: "نام کاربری/رمز نامعتبر (رمز حداقل ۶ کاراکتر)" }));
        }
        const salt = randomSalt();
        const passwordHash = await hashPassword(password, salt);
        await db.createUser(env.DB, { username, passwordHash, salt, isAdmin: true });
        const user = await db.getUserByUsername(env.DB, username);
        const token = await createSession(env, user.id, request);
        return redirect("/", { "Set-Cookie": sessionCookieHeader(token) });
      }
    }

    if (path === "/login") {
      const userCount = await db.countUsers(env.DB);
      if (userCount === 0) return redirect("/setup");
      if (method === "GET") return html(loginPage({ hasUsers: true }));
      if (method === "POST") {
        const form = await request.formData();
        const username = (form.get("username") || "").toString().trim();
        const password = (form.get("password") || "").toString();
        const user = await db.getUserByUsername(env.DB, username);
        if (!user || !(await verifyPassword(password, user.salt, user.password_hash))) {
          return html(loginPage({ hasUsers: true, error: "نام کاربری یا رمز عبور اشتباه است" }));
        }
        const token = await createSession(env, user.id, request);
        if (user.notification_prefs) {
          try {
            const prefs = JSON.parse(user.notification_prefs);
            if (prefs.login_alerts) {
              await db.createNotification(env.DB, user.id, "ورود جدید به حساب", "یک ورود موفق به پنل ثبت شد.");
            }
          } catch {}
        }
        return redirect("/", { "Set-Cookie": sessionCookieHeader(token) });
      }
    }

    if (path === "/logout") {
      const cookies = parseCookies(request);
      if (cookies[SESSION_COOKIE]) await destroySessionByToken(env, cookies[SESSION_COOKIE]);
      return redirect("/login", { "Set-Cookie": `${SESSION_COOKIE}=; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=0` });
    }

    const session = await getCurrentSession(request, env);
    if (!session) return redirect("/login");
    const currentUser = await db.getUserById(env.DB, session.user_id);
    if (!currentUser) return redirect("/login");
    const userId = currentUser.id;

    if (path === "/" && method === "GET") {
      const bots = await db.listBotsForUser(env.DB, userId);
      const initial = bots.slice(0, BOTS_PAGE_SIZE);
      const statsMap = await db.getDailyStatsForBots(env.DB, initial.map((b) => b.id), 7);
      const page = botsPage({ username: currentUser.username, bots, statsMap });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    if (path === "/api/bots/page" && method === "GET") {
      const offset = Number(url.searchParams.get("offset") || 0);
      const limit = Number(url.searchParams.get("limit") || BOTS_PAGE_SIZE);
      const bots = await db.listBotsForUserPage(env.DB, userId, offset, limit + 1);
      const hasMore = bots.length > limit;
      const slice = bots.slice(0, limit);
      const statsMap = await db.getDailyStatsForBots(env.DB, slice.map((b) => b.id), 7);
      const htmlFrag = slice.map((b) => botCardHtml(b, statsMap)).join("");
      return jsonResponse({ html: htmlFrag, hasMore });
    }

    if (path === "/api/bots" && method === "POST") {
      const form = await request.formData();
      const token = (form.get("token") || "").toString().trim();
      const welcome = (form.get("welcome") || "سلام خوش آمدید 👋").toString();
      const emojis = form.getAll("emojis").map((e) => e.toString());
      const smartReaction = form.get("smart_reaction") === "1";

      if (!token) {
        const bots = await db.listBotsForUser(env.DB, userId);
        const page = botsPage({ username: currentUser.username, bots, error: "توکن نمی‌تواند خالی باشد" });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      }
      const me = await tg.getMe(token);
      if (!me.ok) {
        const bots = await db.listBotsForUser(env.DB, userId);
        const page = botsPage({ username: currentUser.username, bots, error: "توکن نامعتبر است یا تلگرام آن را نپذیرفت" });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      }
      const webhookSecret = randomSecretToken();
      const botId = await db.createBot(env.DB, {
        userId,
        token,
        botUsername: "@" + me.result.username,
        emojis: emojis.length ? emojis : ["❤"],
        welcomeMessage: welcome,
        webhookSecret,
        smartReaction,
      });
      const webhookUrl = `${new URL(request.url).origin}/webhook/${botId}`;
      const wh = await tg.setWebhook(token, webhookUrl, webhookSecret);
      if (!wh.ok) await db.setBotError(env.DB, botId, "خطا در ست‌کردن وبهوک: " + (wh.description || ""));

      const bots = await db.listBotsForUser(env.DB, userId);
      const page = botsPage({ username: currentUser.username, bots, message: `ربات ${me.result.username} با موفقیت ساخته شد ✅` });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    if (path === "/api/bots/import" && method === "POST") {
      const form = await request.formData();
      const csvText = (form.get("csv_text") || "").toString();
      const lines = csvText.split("\n").map((l) => l.trim()).filter(Boolean);
      const results = [];
      let ok = 0, fail = 0;
      for (const line of lines) {
        const parsed = parseCsvLine(line);
        if (!parsed) {
          fail++;
          results.push({ ok: false, label: "خط نامعتبر: " + line.slice(0, 30) });
          continue;
        }
        const me = await tg.getMe(parsed.token);
        if (!me.ok) {
          fail++;
          results.push({ ok: false, label: "توکن نامعتبر: " + parsed.token.slice(0, 12) + "…" });
          continue;
        }
        const webhookSecret = randomSecretToken();
        const botId = await db.createBot(env.DB, {
          userId,
          token: parsed.token,
          botUsername: "@" + me.result.username,
          emojis: parsed.emojis,
          welcomeMessage: parsed.welcome,
          webhookSecret,
          smartReaction: false,
        });
        const webhookUrl = `${new URL(request.url).origin}/webhook/${botId}`;
        const wh = await tg.setWebhook(parsed.token, webhookUrl, webhookSecret);
        if (!wh.ok) await db.setBotError(env.DB, botId, "خطا در ست‌کردن وبهوک");
        ok++;
        results.push({ ok: true, label: me.result.username + " ✅" });
      }
      const bots = await db.listBotsForUser(env.DB, userId);
      const page = botsPage({ username: currentUser.username, bots, importResult: { ok, fail, total: lines.length, lines: results } });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    const toggleMatch = path.match(/^\/api\/bots\/(\d+)\/toggle$/);
    if (toggleMatch && method === "POST") {
      const bot = await db.getBotById(env.DB, Number(toggleMatch[1]));
      if (bot && bot.user_id === userId) {
        if (bot.status === "active") {
          await tg.deleteWebhook(bot.token);
          await db.updateBotStatus(env.DB, bot.id, "paused");
        } else {
          const webhookUrl = `${new URL(request.url).origin}/webhook/${bot.id}`;
          const wh = await tg.setWebhook(bot.token, webhookUrl, bot.webhook_secret);
          if (wh.ok) await db.clearBotError(env.DB, bot.id);
          else await db.setBotError(env.DB, bot.id, "خطا در ست‌کردن وبهوک: " + (wh.description || ""));
        }
      }
      return redirect("/");
    }

    const retryWebhookMatch = path.match(/^\/api\/bots\/(\d+)\/retry-webhook$/);
    if (retryWebhookMatch && method === "POST") {
      const bot = await db.getBotById(env.DB, Number(retryWebhookMatch[1]));
      if (bot && bot.user_id === userId) {
        const webhookUrl = `${new URL(request.url).origin}/webhook/${bot.id}`;
        const wh = await tg.setWebhook(bot.token, webhookUrl, bot.webhook_secret);
        if (wh.ok) await db.clearBotError(env.DB, bot.id);
        else await db.setBotError(env.DB, bot.id, "خطا در ست‌کردن وبهوک: " + (wh.description || ""));
      }
      return redirect("/");
    }

    const updateMatch = path.match(/^\/api\/bots\/(\d+)\/update$/);
    if (updateMatch && method === "POST") {
      const bot = await db.getBotById(env.DB, Number(updateMatch[1]));
      if (bot && bot.user_id === userId) {
        const form = await request.formData();
        const emojis = form.getAll("emojis").map((e) => e.toString());
        const welcome = (form.get("welcome") || bot.welcome_message).toString();
        const smartReaction = form.get("smart_reaction") === "1";
        await db.updateBotSettings(env.DB, bot.id, { emojis: emojis.length ? emojis : ["❤"], welcomeMessage: welcome, smartReaction });
      }
      return redirect("/");
    }

    const deleteMatch = path.match(/^\/api\/bots\/(\d+)\/delete$/);
    if (deleteMatch && method === "POST") {
      const bot = await db.getBotById(env.DB, Number(deleteMatch[1]));
      if (bot && bot.user_id === userId) {
        await tg.deleteWebhook(bot.token);
        await db.deleteBot(env.DB, bot.id);
      }
      return redirect("/");
    }

    if (path === "/react" && method === "GET") {
      const bots = await db.listBotsForUser(env.DB, userId);
      const history = await db.listLinkReactionsForUser(env.DB, userId);
      const recentLinks = await db.listRecentLinks(env.DB, userId);
      const maxBots = Math.max(1, Math.min(MAX_LINK_REACTION_BOTS, bots.length || 1));
      const page = linkReactPage({ bots, history, maxBots, recentLinks });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    if (path === "/api/link-preview" && method === "GET") {
      const link = url.searchParams.get("link") || "";
      const parsed = parseMessageLink(link);
      if (!parsed) return jsonResponse({ ok: false, reason: "لینک نامعتبر" });
      const preview = await fetchLinkPreview(parsed.publicUsername, parsed.messageId);
      return jsonResponse(preview);
    }

    if (path === "/api/react-link" && method === "POST") {
      const bots = await db.listBotsForUser(env.DB, userId);
      const history = await db.listLinkReactionsForUser(env.DB, userId);
      const recentLinks = await db.listRecentLinks(env.DB, userId);
      const maxBots = Math.max(1, Math.min(MAX_LINK_REACTION_BOTS, bots.length || 1));

      const form = await request.formData();
      const links = form.getAll("links").map((v) => v.toString().trim()).filter(Boolean).slice(0, MAX_LINKS_PER_REQUEST);
      const emojiMode = (form.get("emoji_mode") || "random").toString();
      const fixedEmoji = (form.get("fixed_emoji") || "").toString();
      const isBig = form.get("is_big") === "1";
      const delaySeconds = Math.max(0, Math.min(5, parseFloat(form.get("delay_seconds") || "0.3") || 0));
      const selectedIds = form.getAll("bot_ids").map((v) => Number(v));

      const renderError = async (msg) => {
        const page = linkReactPage({ bots, history, maxBots, recentLinks, error: msg });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      };

      if (links.length === 0) return renderError("حداقل یک لینک وارد کن");
      if (selectedIds.length === 0) return renderError("حداقل یک ربات را انتخاب کن");
      if (selectedIds.length > MAX_LINK_REACTION_BOTS) return renderError(`حداکثر ${MAX_LINK_REACTION_BOTS} ربات در هر بار مجاز است`);
      if (emojiMode === "fixed" && !ALLOWED_REACTION_EMOJIS.includes(fixedEmoji)) return renderError("ایموجی ثابت انتخاب‌شده معتبر نیست");

      const ownedBots = bots.filter((b) => selectedIds.includes(b.id));
      const perLink = [];
      let totalSuccess = 0, totalFail = 0;

      for (const link of links) {
        const parsed = parseMessageLink(link);
        if (!parsed) {
          perLink.push({ link, error: "لینک نامعتبر است", items: [] });
          continue;
        }
        const items = [];
        let successCount = 0, failCount = 0;
        for (const bot of ownedBots) {
          const botEmojis = JSON.parse(bot.emojis || '["❤"]');
          const emoji = emojiMode === "fixed" ? fixedEmoji : pickRandomEmoji(botEmojis);
          const res = await tg.setMessageReaction(bot.token, parsed.chatId, parsed.messageId, emoji, isBig);
          if (res.ok) {
            successCount++; totalSuccess++;
            await db.incrementReaction(env.DB, bot.id);
            items.push({ botId: bot.id, botUsername: bot.bot_username, emoji, ok: true });
          } else {
            failCount++; totalFail++;
            items.push({ botId: bot.id, botUsername: bot.bot_username, emoji, ok: false, reason: explainTelegramError(res.description || "") });
          }
          await sleep(Math.round(delaySeconds * 1000) + Math.floor(Math.random() * 100));
        }
        await db.insertLinkReaction(env.DB, {
          userId, messageLink: link, chatId: parsed.chatId, messageId: parsed.messageId,
          requestedCount: ownedBots.length, successCount, failCount, emojiMode,
          fixedEmoji: emojiMode === "fixed" ? fixedEmoji : null, details: items,
        });
        await db.touchRecentLink(env.DB, userId, link);
        perLink.push({ link, items });
      }

      const prefs = currentUser.notification_prefs ? JSON.parse(currentUser.notification_prefs) : {};
      if (prefs.error_alerts && totalFail > 0) {
        await db.createNotification(env.DB, userId, "چند ری‌اکشن ناموفق بود", `${totalFail} مورد از ${totalSuccess + totalFail} ری‌اکشن با خطا مواجه شد.`);
      }

      const freshHistory = await db.listLinkReactionsForUser(env.DB, userId);
      const freshRecent = await db.listRecentLinks(env.DB, userId);
      const page = linkReactPage({
        bots, history: freshHistory, maxBots, recentLinks: freshRecent,
        result: { total: ownedBots.length * links.length, successCount: totalSuccess, failCount: totalFail, perLink },
      });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    const retryMatch = path.match(/^\/api\/react-link\/retry\/(\d+)$/);
    if (retryMatch && method === "POST") {
      const row = await db.getLinkReactionById(env.DB, Number(retryMatch[1]), userId);
      if (row) {
        const details = JSON.parse(row.details || "[]");
        const failedIds = details.filter((d) => !d.ok).map((d) => d.botId).filter(Boolean);
        const bots = await db.listBotsForUser(env.DB, userId);
        const ownedBots = bots.filter((b) => failedIds.includes(b.id));
        const items = [];
        let successCount = 0, failCount = 0;
        for (const bot of ownedBots) {
          const botEmojis = JSON.parse(bot.emojis || '["❤"]');
          const emoji = row.emoji_mode === "fixed" ? row.fixed_emoji : pickRandomEmoji(botEmojis);
          const res = await tg.setMessageReaction(bot.token, row.chat_id, row.message_id, emoji, false);
          if (res.ok) {
            successCount++;
            await db.incrementReaction(env.DB, bot.id);
            items.push({ botId: bot.id, botUsername: bot.bot_username, emoji, ok: true });
          } else {
            failCount++;
            items.push({ botId: bot.id, botUsername: bot.bot_username, emoji, ok: false, reason: explainTelegramError(res.description || "") });
          }
          await sleep(200);
        }
        await db.insertLinkReaction(env.DB, {
          userId, messageLink: row.message_link, chatId: row.chat_id, messageId: row.message_id,
          requestedCount: ownedBots.length, successCount, failCount, emojiMode: row.emoji_mode,
          fixedEmoji: row.fixed_emoji, details: items,
        });
      }
      return redirect("/react");
    }

    if (path === "/account" && method === "GET") {
      const sessions = await db.listSessions(env.DB, userId);
      const notifPrefs = currentUser.notification_prefs ? JSON.parse(currentUser.notification_prefs) : {};
      const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    if (path === "/api/account/username" && method === "POST") {
      const form = await request.formData();
      const newUsername = (form.get("username") || "").toString().trim();
      const sessions = await db.listSessions(env.DB, userId);
      const notifPrefs = currentUser.notification_prefs ? JSON.parse(currentUser.notification_prefs) : {};
      if (newUsername.length < 3) {
        const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs, error: "نام کاربری باید حداقل ۳ کاراکتر باشد" });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      }
      const result = await db.updateUsername(env.DB, userId, newUsername);
      if (!result.ok) {
        const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs, error: result.error });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      }
      const page = accountPage({ username: newUsername, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs, message: "نام کاربری با موفقیت تغییر کرد ✅" });
      return html(await renderPage(env, { active: page.active, currentUser: { ...currentUser, username: newUsername }, title: page.title, bodyHtml: page.bodyHtml }));
    }

    if (path === "/api/account/password" && method === "POST") {
      const form = await request.formData();
      const current = (form.get("current") || "").toString();
      const newPass = (form.get("new") || "").toString();
      const sessions = await db.listSessions(env.DB, userId);
      const notifPrefs = currentUser.notification_prefs ? JSON.parse(currentUser.notification_prefs) : {};
      const valid = await verifyPassword(current, currentUser.salt, currentUser.password_hash);
      if (!valid) {
        const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs, error: "رمز عبور فعلی اشتباه است" });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      }
      if (newPass.length < 6) {
        const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs, error: "رمز عبور جدید باید حداقل ۶ کاراکتر باشد" });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      }
      const newSalt = randomSalt();
      const newHash = await hashPassword(newPass, newSalt);
      await db.updatePassword(env.DB, userId, newSalt, newHash);
      const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs, message: "رمز عبور با موفقیت تغییر کرد ✅" });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    if (path === "/api/account/avatar" && method === "POST") {
      let body;
      try {
        body = await request.json();
      } catch {
        return jsonResponse({ ok: false }, 400);
      }
      const avatar = (body.avatar || "").toString();
      if (!avatar.startsWith("data:image/") || avatar.length > 400000) {
        return jsonResponse({ ok: false, reason: "تصویر نامعتبر یا خیلی بزرگ است" }, 400);
      }
      await db.updateAvatar(env.DB, userId, avatar);
      return jsonResponse({ ok: true });
    }

    if (path === "/api/account/avatar" && method === "DELETE") {
      await db.updateAvatar(env.DB, userId, null);
      return jsonResponse({ ok: true });
    }

    if (path === "/api/account/notifications" && method === "POST") {
      const form = await request.formData();
      const prefs = {
        error_alerts: form.get("error_alerts") === "1",
        login_alerts: form.get("login_alerts") === "1",
        weekly_summary: form.get("weekly_summary") === "1",
      };
      await db.updateNotificationPrefs(env.DB, userId, prefs);
      const sessions = await db.listSessions(env.DB, userId);
      const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs: prefs, message: "تنظیمات اعلان‌ها ذخیره شد ✅" });
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    const revokeMatch = path.match(/^\/api\/account\/sessions\/(\d+)\/revoke$/);
    if (revokeMatch && method === "POST") {
      await db.deleteSession(env.DB, Number(revokeMatch[1]), userId);
      return redirect("/account");
    }

    if (path === "/api/account/sessions/revoke-all" && method === "POST") {
      await db.deleteOtherSessions(env.DB, userId, session.id);
      return redirect("/account");
    }

    if (path === "/api/account/delete" && method === "POST") {
      const form = await request.formData();
      const password = (form.get("password") || "").toString();
      const valid = await verifyPassword(password, currentUser.salt, currentUser.password_hash);
      if (!valid) {
        const sessions = await db.listSessions(env.DB, userId);
        const notifPrefs = currentUser.notification_prefs ? JSON.parse(currentUser.notification_prefs) : {};
        const page = accountPage({ username: currentUser.username, avatarUrl: currentUser.avatar_url, sessions, currentSessionId: session.id, notifPrefs, error: "رمز عبور اشتباه است، حساب حذف نشد" });
        return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
      }
      const bots = await db.listBotsForUser(env.DB, userId);
      await Promise.all(bots.map((bot) => tg.deleteWebhook(bot.token).catch(() => {})));
      await db.deleteUser(env.DB, userId);
      return redirect("/login", { "Set-Cookie": `${SESSION_COOKIE}=; HttpOnly; Secure; SameSite=Lax; Path=/; Max-Age=0` });
    }

    if (path === "/api/notifications/read-all" && method === "POST") {
      await db.markAllNotificationsRead(env.DB, userId);
      return jsonResponse({ ok: true });
    }

    if (path === "/about" && method === "GET") {
      const page = aboutPage();
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    if (path === "/creator" && method === "GET") {
      const page = creatorPage();
      return html(await renderPage(env, { active: page.active, currentUser, title: page.title, bodyHtml: page.bodyHtml }));
    }

    return new Response("Not Found", { status: 404 });
}

function diagnosticPage(title, description, steps) {
  return `<!DOCTYPE html>
<html lang="fa" dir="rtl"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${esc(title)}</title>
<style>
  body { font-family:Tahoma,sans-serif; background:#0b0906; color:#f3ecd9; margin:0; padding:24px; }
  .box { max-width:560px; margin:40px auto; background:rgba(255,255,255,0.04); border:1px solid rgba(230,180,90,0.25); border-radius:18px; padding:26px; }
  h1 { color:#f0c25a; font-size:1.3em; margin-bottom:12px; }
  p { line-height:1.9; color:#c9bd9e; font-size:14px; }
  ol { color:#c9bd9e; font-size:13.5px; line-height:2; padding-inline-start:22px; }
  code { background:rgba(255,255,255,0.08); padding:2px 8px; border-radius:6px; color:#f0c25a; direction:ltr; display:inline-block; }
  .step-box { background:rgba(0,0,0,0.25); border-radius:12px; padding:14px 16px; margin-top:14px; }
</style></head>
<body>
  <div class="box">
    <h1>⚠️ ${esc(title)}</h1>
    <p>${description}</p>
    ${steps ? `<div class="step-box"><ol>${steps.map((s) => `<li>${s}</li>`).join("")}</ol></div>` : ""}
  </div>
</body></html>`;
}

export default {
  async fetch(request, env, ctx) {
    if (!env || !env.DB) {
      return html(
        diagnosticPage(
          "دیتابیس (D1) وصل نشده",
          "بایندینگ <code>DB</code> برای این Worker تنظیم نشده. یعنی بخش <code>[[d1_databases]]</code> در <code>wrangler.toml</code> درست نیست یا هنوز دیپلوی نشده.",
          [
            "مطمئن شو در <code>wrangler.toml</code> مقدار <code>binding = \"DB\"</code> و <code>database_id</code> درست (خروجی <code>wrangler d1 create</code>) تنظیم شده",
            "دوباره دیپلوی کن: <code>wrangler deploy</code>",
          ]
        ),
        500
      );
    }

    try {
      await ensureDatabase(env);
    } catch (err) {
      console.error("Database initialization failed:", err && err.stack ? err.stack : err);
      const msg = String((err && err.message) || err || "نامشخص");
      return html(
        diagnosticPage(
          "راه‌اندازی خودکار دیتابیس ناموفق بود",
          `Worker سعی کرد جدول‌های لازم رو خودش توی D1 بسازه ولی خطا داد: <code>${esc(msg.slice(0, 200))}</code>`,
          [
            "مطمئن شو دیتابیس D1 که بایند کردی درست ساخته شده و بایندینگ <code>DB</code> به همون اشاره می‌کنه",
            "مطمئن شو توکن/اکانت Cloudflare دسترسی نوشتن روی این D1 database رو داره",
            "برای دیدن جزئیات کامل خطا: <code>wrangler tail</code> یا تب Logs در Cloudflare Dashboard",
            "بعد از رفع مشکل، صفحه رو رفرش کن — راه‌اندازی به‌صورت خودکار دوباره امتحان می‌شه",
          ]
        ),
        500
      );
    }

    try {
      return await handleRequest(request, env, ctx);
    } catch (err) {
      console.error("Unhandled error in Worker:", err && err.stack ? err.stack : err);

      const msg = String((err && err.message) || err || "");
      if (/no such table|no such column/i.test(msg)) {
        return html(
          diagnosticPage(
            "خطای غیرمنتظره در ساختار دیتابیس",
            `دیتابیس D1 وصل و راه‌اندازی شده، اما هنگام اجرای کوئری خطا داد: <code>${esc(msg.slice(0, 160))}</code>. این معمولاً یعنی دیتابیس توسط ابزار دیگری (خارج از این Worker) دستکاری شده.`,
            [
              "صفحه رو یک‌بار رفرش کن؛ راه‌اندازی خودکار دوباره بررسی می‌کنه",
              "اگه ادامه داشت، جزئیات کامل رو با <code>wrangler tail</code> یا تب Logs در Cloudflare Dashboard ببین",
            ]
          ),
          500
        );
      }

      return html(
        diagnosticPage(
          "خطای غیرمنتظره در Worker",
          `یک خطای داخلی رخ داد: <code>${esc(msg.slice(0, 200) || "نامشخص")}</code>`,
          [
            "برای دیدن جزئیات کامل خطا، این دستور رو در ترمینال اجرا کن و دوباره صفحه رو باز کن:",
            "<code>wrangler tail</code>",
            "یا از پنل Cloudflare Dashboard → Workers → این Worker → تب Logs استفاده کن",
          ]
        ),
        500
      );
    }
  },
};
